            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF8 id format "Product|123" (EF9 defaults to key-only)
            entity.HasDiscriminatorInJsonId();

            // Preserve EF8 shadow __id property (EF9 maps key directly to JSON id)
            entity.HasShadowId();
        });
    }
}
